{
  "verses": [
    {
      "n": 18,
      "column": "left",
      "text": "Un manni Laudis dsih-\nwohs eekſch Meera-Nomneem /\nmeertgôß Dsihwokkôß/un nebih-\njajama Duſſetchanâ.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Bet Kruſha buhs/kur lei-\njâ us Meschu irr ja-eet / un tas\nPilsfahts taps femmi paſem-\nmohts.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Swehtigee eſtat juhs/\nkas juhs fehjat pee wiſſohn lib-\ndenn Mallahin / kas juhs ta\nWehrſcha un Eheſta Rahju uſ\nturren tuhtat.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Aj tew tu Pohſtitajs!\nkas tu pats ne eſti poḥ-\nsſihts/un tu Wiltigajs/\nprect co ne kas irr wiltigi turre-\njecs / kad tu to Pohſtitchanu\nbulſt pabeidsis / tavſt tu pats\npohſtitſts/ kad tu rabeigſi wilti-\ngi turretees/ tad taps prett tew\natkak wiltigi darrihts.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "KUNGGS / eſt mums\nſchehligs/us tewi gaidam mehs/\neſt winno Elſons Rihtôß / ir\nmuhsu Peſtifchana Behou\nLaika.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Laid tee Laudis behg no ta\nTrohſſna Skannas/ lai tee Pa-\ngani iſkaifitt tohp/ kad tu pa-\nangſtinajecs.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Tad taps juhsu Lan-\njuns ſakrahts/ itt ka Wabbe-\ntohp ſakrahtas/ itt ka tee Si-\nri ſkraida / ta taps us win-\nskraidihts.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Tas KUNGGSirr pa-a-\nſtinahts/ jo wiꞥſch dsihwo A-\nſribâ/ wiꞥſch irr Zianu peepili-\nar Teetu un Taifnibu.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Un tawa Laika buhs D-\nziba/ Stiprams / Peſtifchan-\nGudriba un Atſifschana :\nKUNGGA Biſjaſchana bi-\nwixxa Manta.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Redſi / winno Suht-\nbrehz ahra / tee Wehſtineſcht-\nMeera gauschi raud.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Tee ſtaigati Zelfi irr p-\nſiti/ kas us Tekkahm ſtaig-\ntas mittejahs. Wiꞥſch isnil-\nna to Derribu/ wiꞥſch apſu-\ntohs Pilsfahtus/ un ne zeemi-\nlahou Zilwektu.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Ta Gemme behdajahs-\nwaid/ Libbanus irr nejauki-\nzirſts / Sarons irr tappis\nTuksneſe/ ir Bahsans/ ir Ka-\nmels ruhz.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Nu es zelſchohs / fa-\ntas KUNGGS : Nu tapchu-\npa angſtinachts / un augsti fl-\nwehts.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Juhs eetat ar Salme-\napgruhtinati / Ringgajus ju-\ndſemdefeet/ juhsu Lepniba ju-\nnorih ka Uggunß.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Jo tee Laudis tapatt-\nSkateis tohp dedſinati / itt-\nnezirſti Chriſthli taps tee ar U-\nguni ſadedſinati.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
